/**
 * flow-doc-generator.js — Generate technical documentation for Salesforce flows from XML metadata.
 *
 * Parses flow XML files, extracts metadata (trigger, decisions, DML, variables, etc.),
 * and generates markdown documentation per flow, category indexes, a master index,
 * and XML description strings (max 255 chars for the <description> tag).
 *
 * Usage:
 *   node scripts/flow-doc-generator.js FlowApiName                   # Document a single flow
 *   node scripts/flow-doc-generator.js --category account            # All flows in a category
 *   node scripts/flow-doc-generator.js --xml-description-only        # JSON of XML descriptions
 *   node scripts/flow-doc-generator.js --index-only                  # Regenerate indexes only
 *   node scripts/flow-doc-generator.js FlowName --lightweight        # Abbreviated doc
 *   node scripts/flow-doc-generator.js FlowName --dry-run            # Preview without writing
 *   node scripts/flow-doc-generator.js --full                        # Default depth mode
 *
 * Options:
 *   --metadata-path <path>      Path to SFDX metadata directory (default: force-app/main/default)
 *   --docs-path <path>          Path to flow docs output directory (default: docs/flows)
 *   --categories-path <path>    Path to flow categories file (default: <docs-path>/flow-categories.json)
 *                                JSON: { "category_name": ["FlowName1", ...] }
 *                                JS module: exports a categorize(flowName) function
 *   --filters-path <path>       Path to flow-filters.json for skip lists (default: none — no filters)
 *   --category <name>           Process all flows in a category
 *   --full                      Full documentation (default)
 *   --lightweight               Abbreviated doc: Purpose + Trigger + Dependencies only
 *   --dry-run                   Preview without writing files
 *   --xml-description-only      Output XML descriptions as JSON to stdout
 *   --index-only                Only regenerate index files
 *   --project-name <name>       Project name for master index header (default: "Salesforce Project")
 *   --help                      Show this help message
 *
 * Exit codes:
 *   0 — Success
 *   1 — Error (missing paths, bad args)
 */

const fs = require("fs");
const path = require("path");

const REPO_ROOT = path.join(__dirname, "..");

// ---------------------------------------------------------------------------
// CLI argument parsing
