function getArgValue(argList, name) {
  const idx = argList.indexOf(name);
  if (idx === -1 || idx + 1 >= argList.length) return null;
  return argList[idx + 1];
}

// Resolve paths from CLI args
const metadataRel = getArgValue(args, "--metadata-path") || "force-app/main/default";
const docsRel = getArgValue(args, "--docs-path") || "docs/flows";
const FLOW_DIR = path.resolve(REPO_ROOT, metadataRel, "flows");
const DOCS_DIR = path.resolve(REPO_ROOT, docsRel);
const PROJECT_NAME = getArgValue(args, "--project-name") || "Salesforce Project";

// ---------------------------------------------------------------------------
// Load categories (optional — falls back to "other" for all flows)
// ---------------------------------------------------------------------------

const categoriesPathArg = getArgValue(args, "--categories-path");
const categoriesPath = categoriesPathArg
  ? path.resolve(REPO_ROOT, categoriesPathArg)
  : path.join(DOCS_DIR, "flow-categories.json");

let categorizeFn;
let CATEGORY_LABELS = {};

if (fs.existsSync(categoriesPath)) {
  if (categoriesPath.endsWith(".js")) {
    // JS module that exports a categorize(name) function and optionally CATEGORY_LABELS
    const mod = require(categoriesPath);
    categorizeFn = mod.categorize || mod.cat || mod;
    if (mod.CATEGORY_LABELS) CATEGORY_LABELS = mod.CATEGORY_LABELS;
  } else {
    // JSON map: { "category_name": ["FlowName1", ...] }
    const catMap = JSON.parse(fs.readFileSync(categoriesPath, "utf8"));
    const flowToCategory = {};
    for (const [cat, flows] of Object.entries(catMap)) {
      if (cat === "_labels") {
        // Optional labels block: { "_labels": { "api": "API", ... } }
        Object.assign(CATEGORY_LABELS, flows);
        continue;
      }
      for (const fn of flows) {
        flowToCategory[fn] = cat;
      }
    }
    categorizeFn = (name) => flowToCategory[name] || "other";
  }
} else {
  // No categories file — everything goes to "other"
  categorizeFn = () => "other";
}

function categorize(name) {
  // Check skip filters first
  if (skipSets.temp.has(name)) return "SKIP_temp";
  if (skipSets.onetime.has(name)) return "SKIP_onetime";
  if (skipSets.sunset.has(name)) return "SKIP_sunset";
  if (skipSets.platform.has(name)) return "SKIP_platform";
  return categorizeFn(name);
}

function isSkipCategory(cat) {
  return cat.startsWith("SKIP_");
}

// ---------------------------------------------------------------------------
// Load filters (optional — skip lists for temp, sunset, onetime, platform flows)
// ---------------------------------------------------------------------------

const filtersPathArg = getArgValue(args, "--filters-path");
const filtersPath = filtersPathArg ? path.resolve(REPO_ROOT, filtersPathArg) : null;

const skipSets = { temp: new Set(), onetime: new Set(), sunset: new Set(), platform: new Set() };

if (filtersPath && fs.existsSync(filtersPath)) {
  const filters = JSON.parse(fs.readFileSync(filtersPath, "utf8"));
  if (filters.skip_temp) skipSets.temp = new Set(filters.skip_temp.explicit || []);
  if (filters.skip_onetime) skipSets.onetime = new Set(filters.skip_onetime.explicit || []);
  if (filters.skip_sunset) skipSets.sunset = new Set(filters.skip_sunset.explicit || []);
  if (filters.skip_platform) skipSets.platform = new Set(filters.skip_platform.explicit || []);
}

// ---------------------------------------------------------------------------
// XML Parsing helpers — regex-based for predictable Salesforce flow XML
// ---------------------------------------------------------------------------

function extractTopLevel(xml, tag) {
  const re = new RegExp(`<${tag}>([\\s\\S]*?)</${tag}>`);
  const m = xml.match(re);
  return m ? decodeXmlEntities(m[1].trim()) : null;
}

function decodeXmlEntities(s) {
  return s
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&apos;/g, "'");
}

function extractAllBlocks(xml, tag) {
  const re = new RegExp(`<${tag}>([\\s\\S]*?)</${tag}>`, "g");
  const results = [];
  let m;
  while ((m = re.exec(xml)) !== null) {
    results.push(m[1]);
  }
  return results;
}

function extractChild(block, tag) {
  const re = new RegExp(`<${tag}>([\\s\\S]*?)</${tag}>`);
  const m = block.match(re);
  return m ? decodeXmlEntities(m[1].trim()) : null;
}

// ---------------------------------------------------------------------------
// Flow XML Parser
// ---------------------------------------------------------------------------

function parseFlowXml(flowName) {
  const filePath = path.join(FLOW_DIR, `${flowName}.flow-meta.xml`);
  if (!fs.existsSync(filePath)) {
    return null;
  }
  const xml = fs.readFileSync(filePath, "utf8");
  return parseFlowXmlContent(xml, flowName);
}

function parseFlowXmlContent(xml, flowName) {
  const flow = {};
  flow.apiName = flowName;
  flow.label = extractTopLevel(xml, "label") || flowName.replace(/_/g, " ");
  flow.description = extractTopLevel(xml, "description") || "";
  flow.apiVersion = extractTopLevel(xml, "apiVersion") || "";
  flow.processType = extractTopLevel(xml, "processType") || "";
  flow.status = extractTopLevel(xml, "status") || "";
  flow.interviewLabel = extractTopLevel(xml, "interviewLabel") || "";
  flow.isTemplate = xml.includes("<isTemplate>true</isTemplate>");

  // Parse <start> block
  const startBlock = extractAllBlocks(xml, "start")[0] || "";
  flow.triggerType = extractChild(startBlock, "triggerType") || "";
  flow.triggerObject = extractChild(startBlock, "object") || "";
  flow.recordTriggerType = extractChild(startBlock, "recordTriggerType") || "";
  flow.doesRequireRecordChangedToMeetCriteria = startBlock.includes(
    "<doesRequireRecordChangedToMeetCriteria>true</doesRequireRecordChangedToMeetCriteria>"
  );

  // Schedule details
  const scheduleBlock = extractChild(startBlock, "schedule") || "";
  if (scheduleBlock) {
    flow.scheduleFrequency = extractChild(scheduleBlock, "frequency") || "";
    flow.scheduleStartDate = extractChild(scheduleBlock, "startDate") || "";
    flow.scheduleStartTime = extractChild(scheduleBlock, "startTime") || "";
  }

  // Entry conditions (filters in <start>)
  flow.entryConditions = [];
  const filterBlocks = extractAllBlocks(startBlock, "filters");
  for (const fb of filterBlocks) {
    const field = extractChild(fb, "field") || "";
    const operator = extractChild(fb, "operator") || "";
    let value =
      extractChild(fb, "stringValue") ||
      extractChild(fb, "booleanValue") ||
      extractChild(fb, "numberValue") ||
      extractChild(fb, "elementReference") ||
      "";
    flow.entryConditions.push({ field, operator, value });
  }
  flow.filterLogic = extractChild(startBlock, "filterLogic") || "";

  // Scheduled paths
  flow.scheduledPaths =
    extractAllBlocks(startBlock, "scheduledPaths").length > 0;

  // Parse decisions
  flow.decisions = [];
  for (const block of extractAllBlocks(xml, "decisions")) {
    const name = extractChild(block, "name") || "";
    const label = extractChild(block, "label") || "";
    const rules = extractAllBlocks(block, "rules");
    const ruleLabels = rules.map(
      (r) => extractChild(r, "label") || extractChild(r, "name") || ""
    );
    const defaultLabel =
      extractChild(block, "defaultConnectorLabel") || "Default";
    flow.decisions.push({ name, label, ruleLabels, defaultLabel });
  }

  // Parse record lookups (Get Records)
  flow.recordLookups = [];
  for (const block of extractAllBlocks(xml, "recordLookups")) {
    const name = extractChild(block, "name") || "";
    const label = extractChild(block, "label") || "";
    const object = extractChild(block, "object") || "";
    flow.recordLookups.push({ name, label, object });
  }

  // Parse record creates
  flow.recordCreates = [];
  for (const block of extractAllBlocks(xml, "recordCreates")) {
    const name = extractChild(block, "name") || "";
    const label = extractChild(block, "label") || "";
    const object =
      extractChild(block, "object") ||
      extractChild(block, "inputReference") ||
      "";
    flow.recordCreates.push({ name, label, object });
  }

  // Parse record updates
  flow.recordUpdates = [];
  for (const block of extractAllBlocks(xml, "recordUpdates")) {
    const name = extractChild(block, "name") || "";
    const label = extractChild(block, "label") || "";
    const object =
      extractChild(block, "object") ||
      extractChild(block, "inputReference") ||
      "";
    flow.recordUpdates.push({ name, label, object });
  }

  // Parse record deletes
  flow.recordDeletes = [];
  for (const block of extractAllBlocks(xml, "recordDeletes")) {
    const name = extractChild(block, "name") || "";
    const label = extractChild(block, "label") || "";
    const object =
      extractChild(block, "object") ||
      extractChild(block, "inputReference") ||
      "";
    flow.recordDeletes.push({ name, label, object });
  }

  // Parse action calls
  flow.actionCalls = [];
  for (const block of extractAllBlocks(xml, "actionCalls")) {
    const name = extractChild(block, "name") || "";
    const label = extractChild(block, "label") || "";
    const actionName = extractChild(block, "actionName") || "";
    const actionType = extractChild(block, "actionType") || "";
    flow.actionCalls.push({ name, label, actionName, actionType });
  }

  // Parse subflows
  flow.subflows = [];
  for (const block of extractAllBlocks(xml, "subflows")) {
    const name = extractChild(block, "name") || "";
    const label = extractChild(block, "label") || "";
    const flowName = extractChild(block, "flowName") || "";
    flow.subflows.push({ name, label, flowName });
  }

  // Parse variables
  flow.variables = [];
  for (const block of extractAllBlocks(xml, "variables")) {
    const name = extractChild(block, "name") || "";
    const dataType = extractChild(block, "dataType") || "";
    const isCollection = block.includes("<isCollection>true</isCollection>");
    const isInput = block.includes("<isInput>true</isInput>");
    const isOutput = block.includes("<isOutput>true</isOutput>");
    const objectType = extractChild(block, "objectType") || "";
    flow.variables.push({
      name,
      dataType,
      isCollection,
      isInput,
      isOutput,
      objectType,
    });
  }

  // Parse formulas
  flow.formulas = [];
  for (const block of extractAllBlocks(xml, "formulas")) {
    const name = extractChild(block, "name") || "";
    const dataType = extractChild(block, "dataType") || "";
    const expression = extractChild(block, "expression") || "";
    flow.formulas.push({ name, dataType, expression });
  }

  // Parse assignments
  flow.assignments = extractAllBlocks(xml, "assignments").length;

  // Parse screens (for screen flows)
  flow.screens = [];
  for (const block of extractAllBlocks(xml, "screens")) {
    const name = extractChild(block, "name") || "";
    const label = extractChild(block, "label") || "";
    flow.screens.push({ name, label });
  }

  // Custom notifications via actionCalls
  flow.customNotifications = [];
  for (const ac of flow.actionCalls) {
    if (ac.actionType === "customNotificationAction") {
      flow.customNotifications.push(ac.actionName);
    }
  }

  // Collect all sObjects referenced
  const objects = new Set();
  if (flow.triggerObject) objects.add(flow.triggerObject);
  for (const rl of flow.recordLookups) if (rl.object) objects.add(rl.object);
  for (const rc of flow.recordCreates)
    if (rc.object && !rc.object.startsWith("$")) objects.add(rc.object);
  for (const ru of flow.recordUpdates)
    if (ru.object && !ru.object.startsWith("$")) objects.add(ru.object);
  for (const rd of flow.recordDeletes)
    if (rd.object && !rd.object.startsWith("$")) objects.add(rd.object);
  for (const v of flow.variables) if (v.objectType) objects.add(v.objectType);
  flow.referencedObjects = Array.from(objects).sort();

  // Collect Apex classes invoked
  flow.apexClasses = [];
  for (const ac of flow.actionCalls) {
    if (ac.actionType === "apex") {
      flow.apexClasses.push(ac.actionName);
    }
  }

  return flow;
}

// ---------------------------------------------------------------------------
// Trigger description helpers
// ---------------------------------------------------------------------------

function describeTrigger(flow) {
  if (flow.processType === "Flow") {
    return "User-initiated screen flow";
  }
  if (flow.triggerType === "Scheduled") {
    let desc = `Scheduled (${flow.scheduleFrequency || "Unknown frequency"})`;
    if (flow.scheduleStartTime) desc += ` at ${flow.scheduleStartTime}`;
    if (flow.triggerObject) desc += ` on ${flow.triggerObject}`;
    return desc;
  }
  if (
    flow.triggerType === "RecordBeforeSave" ||
    flow.triggerType === "RecordAfterSave"
  ) {
    const timing =
      flow.triggerType === "RecordBeforeSave" ? "Before Save" : "After Save";
    const recTrigger = flow.recordTriggerType || "CreateAndUpdate";
    let desc = `Record-Triggered (${timing}) — ${recTrigger} on ${flow.triggerObject || "Unknown"}`;
    if (flow.scheduledPaths) desc += " (with Scheduled Paths)";
    return desc;
  }
  if (flow.triggerType === "PlatformEvent") {
    return `Platform Event on ${flow.triggerObject || "Unknown"}`;
  }
  if (flow.processType === "AutoLaunchedFlow" && !flow.triggerType) {
    const hasInputs = flow.variables.some((v) => v.isInput);
    return hasInputs ? "Invocable (AutoLaunched)" : "AutoLaunched (no trigger)";
  }
  if (flow.triggerType) {
    return `${flow.triggerType} on ${flow.triggerObject || "Unknown"}`;
  }
  return flow.processType || "Unknown";
}

function describeTypeShort(flow) {
  if (flow.processType === "Flow") return "Screen Flow";
  if (flow.processType === "AutoLaunchedFlow") return "AutoLaunched";
  return flow.processType || "Unknown";
}

function describeTriggerShort(flow) {
  if (flow.processType === "Flow") return "Screen Flow";
  if (flow.triggerType === "Scheduled") {
    return `Scheduled${flow.triggerObject ? " on " + flow.triggerObject : ""}`;
  }
  if (flow.triggerType === "RecordBeforeSave") {
    return `${flow.triggerObject || "?"} — BeforeSave`;
  }
  if (flow.triggerType === "RecordAfterSave") {
    const op = flow.recordTriggerType || "CreateAndUpdate";
    return `${flow.triggerObject || "?"} ${op}`;
  }
  if (flow.processType === "AutoLaunchedFlow" && !flow.triggerType) {
    return flow.variables.some((v) => v.isInput) ? "Invocable" : "AutoLaunched";
  }
  return flow.triggerType || flow.processType || "?";
}

// ---------------------------------------------------------------------------
// Purpose inference
// ---------------------------------------------------------------------------

function inferPurpose(flow) {
  if (flow.description) {
    let desc = flow.description
      .replace(/\s*Docs?:\s*https?:\/\/\S+/gi, "")
      .trim();
    desc = desc.replace(/\.\s*$/, "");
    if (desc.length > 10) return desc + ".";
  }

  const parts = [];
  const name = flow.label || flow.apiName.replace(/_/g, " ");

  if (flow.triggerType === "Scheduled") {
    parts.push(
      `Scheduled flow that processes ${flow.triggerObject || "records"}`
    );
  } else if (
    flow.triggerType === "RecordBeforeSave" ||
    flow.triggerType === "RecordAfterSave"
  ) {
    const timing =
      flow.triggerType === "RecordBeforeSave" ? "before save" : "after save";
    parts.push(`Triggers ${timing} on ${flow.triggerObject || "records"}`);
  } else if (flow.processType === "Flow") {
    parts.push("Screen flow");
  } else {
    parts.push("AutoLaunched flow");
  }

  const actions = [];
  if (flow.recordCreates.length > 0) {
    const objs = [
      ...new Set(flow.recordCreates.map((r) => r.object).filter(Boolean)),
    ];
    actions.push(`creates ${objs.join(", ") || "records"}`);
  }
  if (flow.recordUpdates.length > 0) {
    const objs = [
      ...new Set(
        flow.recordUpdates
          .map((r) => r.object)
          .filter((o) => o && !o.startsWith("$"))
      ),
    ];
    if (objs.length > 0) actions.push(`updates ${objs.join(", ")}`);
    else actions.push("updates triggering record");
  }
  if (flow.recordDeletes.length > 0) {
    const objs = [
      ...new Set(flow.recordDeletes.map((r) => r.object).filter(Boolean)),
    ];
    actions.push(`deletes ${objs.join(", ") || "records"}`);
  }
  if (flow.subflows.length > 0) {
    actions.push(`invokes ${flow.subflows.length} subflow(s)`);
  }

  if (actions.length > 0) parts.push(actions.join(", "));
  return parts.join(" — ") + ".";
}

// ---------------------------------------------------------------------------
// Markdown generators
// ---------------------------------------------------------------------------

function generateFullDoc(flow, category, today) {
  const lines = [];

  lines.push(`# ${flow.label}`);
  lines.push("");
  lines.push(`**Category:** ${category}`);
  lines.push(`**API Name:** ${flow.apiName}`);
  lines.push(`**Type:** ${flow.processType}`);
  lines.push(`**Trigger:** ${describeTrigger(flow)}`);
  lines.push(`**API Version:** ${flow.apiVersion}`);
  lines.push(`**Status:** ${flow.status}`);
  lines.push(`**Last Documented:** ${today}`);
  lines.push("");

  // Purpose
  lines.push("## Purpose");
  lines.push("");
  lines.push(inferPurpose(flow));
  lines.push("");

  // Trigger Details
  lines.push("## Trigger Details");
  lines.push("");
  if (flow.processType === "Flow") {
    lines.push("User-initiated screen flow.");
    if (flow.screens.length > 0) {
      lines.push("");
      lines.push(
        `**Screens:** ${flow.screens.map((s) => s.label || s.name).join(", ")}`
      );
    }
  } else if (flow.triggerType === "Scheduled") {
    lines.push(`- **Object:** ${flow.triggerObject || "N/A"}`);
    lines.push(`- **Frequency:** ${flow.scheduleFrequency || "Unknown"}`);
    if (flow.scheduleStartDate)
      lines.push(`- **Start Date:** ${flow.scheduleStartDate}`);
    if (flow.scheduleStartTime)
      lines.push(`- **Start Time:** ${flow.scheduleStartTime}`);
    if (flow.entryConditions.length > 0) {
      lines.push(`- **Filter Logic:** ${flow.filterLogic}`);
      for (const c of flow.entryConditions) {
        lines.push(`  - \`${c.field}\` ${c.operator} \`${c.value}\``);
      }
    }
  } else if (
    flow.triggerType === "RecordBeforeSave" ||
    flow.triggerType === "RecordAfterSave"
  ) {
    const timing =
      flow.triggerType === "RecordBeforeSave" ? "Before Save" : "After Save";
    lines.push(`- **Object:** ${flow.triggerObject || "Unknown"}`);
    lines.push(`- **Trigger Type:** ${timing}`);
    lines.push(
      `- **Record Trigger:** ${flow.recordTriggerType || "CreateAndUpdate"}`
    );
    if (flow.doesRequireRecordChangedToMeetCriteria) {
      lines.push(
        "- **Requires Change:** Yes (only runs when entry criteria *newly* become true)"
      );
    }
    if (flow.scheduledPaths) {
      lines.push("- **Scheduled Paths:** Yes (async paths defined)");
    }
    if (flow.entryConditions.length > 0) {
      lines.push(`- **Entry Conditions** (${flow.filterLogic}):`);
      for (const c of flow.entryConditions) {
        lines.push(`  - \`${c.field}\` ${c.operator} \`${c.value}\``);
      }
    }
  } else if (flow.processType === "AutoLaunchedFlow" && !flow.triggerType) {
    const inputs = flow.variables.filter((v) => v.isInput);
    if (inputs.length > 0) {
      lines.push(
        "Invocable AutoLaunched flow. Called by other flows or processes."
      );
      lines.push("");
      lines.push("**Input Variables:**");
      for (const v of inputs) {
        lines.push(
          `- \`${v.name}\` (${v.dataType}${v.objectType ? ": " + v.objectType : ""}${v.isCollection ? ", collection" : ""})`
        );
      }
    } else {
      lines.push(
        "AutoLaunched flow with no record trigger. Invoked programmatically or via another flow."
      );
    }
  } else {
    lines.push(describeTrigger(flow));
  }
  lines.push("");

  // Process Logic
  lines.push("## Process Logic");
  lines.push("");
  if (flow.decisions.length > 0) {
    lines.push("### Decisions");
    lines.push("");
    for (const d of flow.decisions) {
      const branches = [...d.ruleLabels, d.defaultLabel].join(", ");
      lines.push(`- **${d.label || d.name}:** ${branches}`);
    }
    lines.push("");
  }
  if (flow.recordLookups.length > 0) {
    lines.push("### Record Lookups (Get Records)");
    lines.push("");
    for (const rl of flow.recordLookups) {
      lines.push(`- **${rl.label || rl.name}:** queries \`${rl.object}\``);
    }
    lines.push("");
  }
  if (flow.recordCreates.length > 0) {
    lines.push("### Record Creates");
    lines.push("");
    for (const rc of flow.recordCreates) {
      lines.push(`- **${rc.label || rc.name}:** creates \`${rc.object}\``);
    }
    lines.push("");
  }
  if (flow.recordUpdates.length > 0) {
    lines.push("### Record Updates");
    lines.push("");
    for (const ru of flow.recordUpdates) {
      const obj = ru.object.startsWith("$")
        ? "triggering record"
        : `\`${ru.object}\``;
      lines.push(`- **${ru.label || ru.name}:** updates ${obj}`);
    }
    lines.push("");
  }
  if (flow.recordDeletes.length > 0) {
    lines.push("### Record Deletes");
    lines.push("");
    for (const rd of flow.recordDeletes) {
      lines.push(`- **${rd.label || rd.name}:** deletes \`${rd.object}\``);
    }
    lines.push("");
  }
  if (flow.subflows.length > 0) {
    lines.push("### Subflow Calls");
    lines.push("");
    for (const sf of flow.subflows) {
      lines.push(`- **${sf.label || sf.name}:** invokes \`${sf.flowName}\``);
    }
    lines.push("");
  }
  if (flow.actionCalls.length > 0) {
    const nonApexNonNotif = flow.actionCalls.filter(
      (a) =>
        a.actionType !== "apex" && a.actionType !== "customNotificationAction"
    );
    const apexActions = flow.actionCalls.filter((a) => a.actionType === "apex");
    if (apexActions.length > 0) {
      lines.push("### Apex Actions");
      lines.push("");
      for (const ac of apexActions) {
        lines.push(`- **${ac.label || ac.name}:** \`${ac.actionName}\``);
      }
      lines.push("");
    }
    if (nonApexNonNotif.length > 0) {
      lines.push("### Action Calls");
      lines.push("");
      for (const ac of nonApexNonNotif) {
        lines.push(
          `- **${ac.label || ac.name}:** ${ac.actionType} — \`${ac.actionName}\``
        );
      }
      lines.push("");
    }
  }
  if (flow.formulas.length > 0) {
    lines.push("### Formulas");
    lines.push("");
    for (const f of flow.formulas) {
      lines.push(`- **${f.name}** (${f.dataType}): \`${f.expression}\``);
    }
    lines.push("");
  }
  if (flow.assignments > 0) {
    lines.push(`**Assignments:** ${flow.assignments} assignment element(s)`);
    lines.push("");
  }

  // Variables table
  if (flow.variables.length > 0) {
    lines.push("## Variables");
    lines.push("");
    lines.push("| Name | Type | Input | Output | Description |");
    lines.push("|------|------|-------|--------|-------------|");
    for (const v of flow.variables) {
      const type = v.objectType
        ? `${v.dataType} (${v.objectType})`
        : v.dataType;
      const typeStr = v.isCollection ? `${type} []` : type;
      lines.push(
        `| ${v.name} | ${typeStr} | ${v.isInput ? "Yes" : "No"} | ${v.isOutput ? "Yes" : "No"} | |`
      );
    }
    lines.push("");
  }

  // Dependencies
  lines.push("## Dependencies");
  lines.push("");
  lines.push(
    `- **Objects:** ${flow.referencedObjects.length > 0 ? flow.referencedObjects.map((o) => "\`" + o + "\`").join(", ") : "None"}`
  );
  const subflowNames = flow.subflows.map((s) => "\`" + s.flowName + "\`");
  lines.push(
    `- **Subflows:** ${subflowNames.length > 0 ? subflowNames.join(", ") : "None"}`
  );
  lines.push(
    `- **Apex:** ${flow.apexClasses.length > 0 ? flow.apexClasses.map((a) => "\`" + a + "\`").join(", ") : "None"}`
  );
  lines.push(
    `- **Custom Notifications:** ${flow.customNotifications.length > 0 ? flow.customNotifications.join(", ") : "None"}`
  );
  lines.push("");

  // Change Log
  lines.push("## Change Log");
  lines.push("");
  lines.push("| Date | Change |");
  lines.push("|------|--------|");
  lines.push(`| ${today} | Initial documentation |`);
  lines.push("");

  return lines.join("\n");
}

function generateLightweightDoc(flow, category, today) {
  const lines = [];

  lines.push(`# ${flow.label}`);
  lines.push("");
  lines.push(`**Category:** ${category}`);
  lines.push(`**API Name:** ${flow.apiName}`);
  lines.push(`**Type:** ${flow.processType}`);
  lines.push(`**Trigger:** ${describeTrigger(flow)}`);
  lines.push(`**Status:** ${flow.status}`);
  lines.push(`**Last Documented:** ${today}`);
  lines.push("");

  lines.push("## Purpose");
  lines.push("");
  lines.push(inferPurpose(flow));
  lines.push("");

  lines.push("## Trigger Details");
  lines.push("");
  if (
    flow.triggerType === "RecordBeforeSave" ||
    flow.triggerType === "RecordAfterSave"
  ) {
    const timing =
      flow.triggerType === "RecordBeforeSave" ? "Before Save" : "After Save";
    lines.push(
      `${timing} on \`${flow.triggerObject || "Unknown"}\` (${flow.recordTriggerType || "CreateAndUpdate"})`
    );
  } else if (flow.triggerType === "Scheduled") {
    lines.push(
      `Scheduled (${flow.scheduleFrequency || "Unknown"})${flow.scheduleStartTime ? " at " + flow.scheduleStartTime : ""}${flow.triggerObject ? " on " + flow.triggerObject : ""}`
    );
  } else if (flow.processType === "Flow") {
    lines.push("User-initiated screen flow.");
  } else {
    lines.push(describeTrigger(flow));
  }
  lines.push("");

  lines.push("## Dependencies");
  lines.push("");
  lines.push(
    `- **Objects:** ${flow.referencedObjects.length > 0 ? flow.referencedObjects.map((o) => "\`" + o + "\`").join(", ") : "None"}`
  );
  const subflowNames = flow.subflows.map((s) => "\`" + s.flowName + "\`");
  lines.push(
    `- **Subflows:** ${subflowNames.length > 0 ? subflowNames.join(", ") : "None"}`
  );
  lines.push(
    `- **Apex:** ${flow.apexClasses.length > 0 ? flow.apexClasses.map((a) => "\`" + a + "\`").join(", ") : "None"}`
  );
  lines.push("");

  lines.push("## Change Log");
  lines.push("");
  lines.push("| Date | Change |");
  lines.push("|------|--------|");
  lines.push(`| ${today} | Initial documentation |`);
  lines.push("");

  return lines.join("\n");
}

// ---------------------------------------------------------------------------
// XML Description generator (max 255 chars)
// ---------------------------------------------------------------------------

function generateXmlDescription(flow, category) {
  const purpose = inferPurpose(flow).replace(/\.$/, "");

  let trigger = "";
  if (
    flow.triggerType === "RecordBeforeSave" ||
    flow.triggerType === "RecordAfterSave"
  ) {
    trigger = `Triggers: ${flow.triggerType === "RecordBeforeSave" ? "Before" : "After"} ${flow.recordTriggerType || "CreateAndUpdate"} on ${flow.triggerObject || "?"}`;
  } else if (flow.triggerType === "Scheduled") {
    trigger = `Triggers: Scheduled${flow.triggerObject ? " on " + flow.triggerObject : ""}`;
  } else if (flow.processType === "Flow") {
    trigger = "Triggers: Screen flow";
  } else {
    trigger = "Triggers: Invocable";
  }

  const actionParts = [];
  if (flow.recordLookups.length > 0)
    actionParts.push(`Get ${flow.recordLookups[0].object || "records"}`);
  if (flow.recordUpdates.length > 0) {
    const obj = flow.recordUpdates[0].object;
    actionParts.push(`Update ${obj && !obj.startsWith("$") ? obj : "record"}`);
  }
  if (flow.recordCreates.length > 0)
    actionParts.push(`Create ${flow.recordCreates[0].object || "records"}`);
  if (flow.recordDeletes.length > 0)
    actionParts.push(`Delete ${flow.recordDeletes[0].object || "records"}`);
  if (flow.subflows.length > 0)
    actionParts.push(`Call ${flow.subflows[0].flowName}`);
  const keyActions = actionParts.slice(0, 3).join(", ");

  const docsRelPath = path.relative(REPO_ROOT, DOCS_DIR).replace(/\\/g, "/");
  const docRef = `Doc: ${docsRelPath}/${category}/${flow.apiName}.md`;

  let desc = `${purpose}. ${trigger}. Key actions: ${keyActions}. ${docRef}`;
  if (desc.length > 255) {
    desc = `${purpose}. ${trigger}. ${docRef}`;
  }
  if (desc.length > 255) {
    const maxPurpose = 255 - trigger.length - docRef.length - 6;
    const truncPurpose = purpose.substring(0, maxPurpose - 3) + "...";
    desc = `${truncPurpose}. ${trigger}. ${docRef}`;
  }
  if (desc.length > 255) {
    desc = desc.substring(0, 252) + "...";
  }

  return desc;
}

// ---------------------------------------------------------------------------
// Index generators
// ---------------------------------------------------------------------------

function generateCategoryIndex(category, flowData) {
  const label = CATEGORY_LABELS[category] || category;
  const today = getToday();
  const lines = [];

  lines.push(`# ${label} Flows`);
  lines.push("");
  lines.push(`**Category:** \`${category}\``);
  lines.push(`**Flow count:** ${flowData.length}`);
  lines.push(`**Last updated:** ${today}`);
  lines.push("");

  lines.push("| Flow | Type | Trigger | Status | Last Documented |");
  lines.push("|------|------|---------|--------|-----------------|");

  for (const fd of flowData.sort((a, b) =>
    a.apiName.localeCompare(b.apiName)
  )) {
    const link = `[${fd.apiName}](./${fd.apiName}.md)`;
    lines.push(
      `| ${link} | ${describeTypeShort(fd)} | ${describeTriggerShort(fd)} | ${fd.status} | ${today} |`
    );
  }
  lines.push("");

  return lines.join("\n");
}

function generateMasterIndex(categoryStats) {
  const today = getToday();
  const lines = [];

  let totalFlows = 0;
  let totalDocumented = 0;
  for (const [cat, stats] of Object.entries(categoryStats)) {
    if (!isSkipCategory(cat)) {
      totalFlows += stats.total;
      totalDocumented += stats.documented;
    }
  }

  lines.push(`# ${PROJECT_NAME} — Flow Documentation Master Index`);
  lines.push("");
  lines.push("**Metadata path:** `" + metadataRel + "/flows/`");
  lines.push(`**Total flows:** ${totalFlows}`);
  lines.push(`**Documented flows:** ${totalDocumented}`);
  lines.push(`**Last updated:** ${today}`);
  lines.push("");
  lines.push("---");
  lines.push("");
  lines.push("## Categories");
  lines.push("");
  lines.push("| Category | Flows | Documented | Index |");
  lines.push("|----------|-------|------------|-------|");

  const sortedCats = Object.keys(categoryStats)
    .filter((k) => !isSkipCategory(k))
    .sort();

  for (const cat of sortedCats) {
    const stats = categoryStats[cat];
    if (!stats) continue;
    const label = CATEGORY_LABELS[cat] || cat;
    const link = `./${cat}/_index.md`;
    lines.push(
      `| [${label}](${link}) | ${stats.total} | ${stats.documented} | [View](${link}) |`
    );
  }
  lines.push("");

  // Skipped section
  const skipCats = Object.entries(categoryStats).filter(([k]) =>
    isSkipCategory(k)
  );
  if (skipCats.length > 0) {
    lines.push("### Skipped (not documented)");
    lines.push("");
    lines.push("| Reason | Count |");
    lines.push("|--------|-------|");
    for (const [cat, stats] of skipCats) {
      lines.push(`| ${cat} | ${stats.total} |`);
    }
    lines.push("");
  }

  lines.push("---");
  lines.push("");

  return lines.join("\n");
}

// ---------------------------------------------------------------------------
// File system helpers
// ---------------------------------------------------------------------------

function ensureDir(dirPath) {
  if (!fs.existsSync(dirPath)) {
    fs.mkdirSync(dirPath, { recursive: true });
  }
}

function getToday() {
  const d = new Date();
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd}`;
}

function getAllFlowNames() {
  if (!fs.existsSync(FLOW_DIR)) {
    console.error(`ERROR: Flow directory not found: ${FLOW_DIR}`);
    process.exit(1);
  }
  return fs
    .readdirSync(FLOW_DIR)
    .filter((f) => f.endsWith(".flow-meta.xml"))
    .map((f) => f.replace(".flow-meta.xml", ""))
    .sort();
}

function readExistingChangeLog(docPath) {
  if (!fs.existsSync(docPath)) return null;
  const content = fs.readFileSync(docPath, "utf8");
  const changeLogMatch = content.match(
    /## Change Log\s*\n\s*\n\s*\| Date \| Change \|\s*\n\s*\|[-|]+\|\s*\n([\s\S]*?)(?:\n\n|\n$|$)/
  );
  if (!changeLogMatch) return null;
  return changeLogMatch[1].trim();
}

function countDocumented(category) {
  const catDir = path.join(DOCS_DIR, category);
  if (!fs.existsSync(catDir)) return 0;
  return fs
    .readdirSync(catDir)
    .filter((f) => f.endsWith(".md") && f !== "_index.md").length;
}

// ---------------------------------------------------------------------------
// Main actions
// ---------------------------------------------------------------------------

function documentFlow(flowName, opts) {
  const category = categorize(flowName);
  if (isSkipCategory(category)) {
    console.log(`SKIP: ${flowName} is in skip category ${category}`);
    return { skipped: true, flowName, category };
  }

  const flow = parseFlowXml(flowName);
  if (!flow) {
    console.error(`ERROR: Flow XML not found for ${flowName}`);
    return { error: true, flowName };
  }

  if (flow.isTemplate) {
    console.log(`SKIP: ${flowName} is a template flow`);
    return { skipped: true, flowName, category: "template" };
  }

  // Skip managed package flows
  if (/__/.test(flowName) && /^[a-zA-Z0-9]+__/.test(flowName)) {
    const prefix = flowName.split("__")[0];
    if (prefix.length <= 10 && prefix !== flowName) {
      console.log(
        `SKIP: ${flowName} appears to be a managed package flow (prefix: ${prefix})`
      );
      return { skipped: true, flowName, category: "managed_package" };
    }
  }

  const today = getToday();
  const lightweight = opts.lightweight || false;
  const dryRun = opts.dryRun || false;

  const doc = lightweight
    ? generateLightweightDoc(flow, category, today)
    : generateFullDoc(flow, category, today);

  const docPath = path.join(DOCS_DIR, category, `${flowName}.md`);
  if (!dryRun && !lightweight) {
    const existingLog = readExistingChangeLog(docPath);
    if (existingLog) {
      const newEntry = `| ${today} | Documentation regenerated |`;
      const updatedDoc = doc.replace(
        `| ${today} | Initial documentation |`,
        existingLog + "\n" + newEntry
      );
      ensureDir(path.join(DOCS_DIR, category));
      fs.writeFileSync(docPath, updatedDoc, "utf8");
      console.log(`UPDATED: ${docPath}`);
      return { written: true, flowName, category, path: docPath, flow };
    }
  }

  if (dryRun) {
    console.log(`DRY-RUN: Would write ${docPath}`);
    console.log("---");
    console.log(
      doc.substring(0, 500) + (doc.length > 500 ? "\n...(truncated)" : "")
    );
    console.log("---");
    return { dryRun: true, flowName, category, path: docPath, flow };
  }

  ensureDir(path.join(DOCS_DIR, category));
  fs.writeFileSync(docPath, doc, "utf8");
  console.log(`WROTE: ${docPath}`);
  return { written: true, flowName, category, path: docPath, flow };
}

function generateXmlDescriptions(flowNames) {
  const descriptions = {};
  for (const flowName of flowNames) {
    const category = categorize(flowName);
    if (isSkipCategory(category)) continue;

    const flow = parseFlowXml(flowName);
    if (!flow) continue;
    if (flow.isTemplate) continue;

    descriptions[flowName] = generateXmlDescription(flow, category);
  }
  return descriptions;
}

function updateCategoryIndex(category, opts) {
  const dryRun = opts.dryRun || false;
  const catDir = path.join(DOCS_DIR, category);
  const allFlows = getAllFlowNames();
  const categoryFlows = allFlows.filter((n) => categorize(n) === category);

  const flowData = [];
  for (const flowName of categoryFlows) {
    const flow = parseFlowXml(flowName);
    if (!flow) continue;
    if (flow.isTemplate) continue;
    flowData.push(flow);
  }

  // Preserve Overview and Process Diagram sections from existing index
  const indexPath = path.join(catDir, "_index.md");
  let preservedSections = "";
  if (fs.existsSync(indexPath)) {
    const existing = fs.readFileSync(indexPath, "utf8");
    const overviewMatch = existing.match(
      /(## Overview[\s\S]*?)(?=\n\| Flow \||\n## All|\n---\s*$)/
    );
    if (overviewMatch) {
      preservedSections = overviewMatch[1].trim();
    }
  }

  const label = CATEGORY_LABELS[category] || category;
  const today = getToday();
  const documented = countDocumented(category);

  const lines = [];
  lines.push(`# ${label} Flows`);
  lines.push("");
  lines.push(`**Category:** \`${category}\``);
  lines.push(`**Flow count:** ${categoryFlows.length}`);
  lines.push(`**Documented:** ${documented}`);
  lines.push(`**Last updated:** ${today}`);
  lines.push("");

  if (preservedSections) {
    lines.push(preservedSections);
    lines.push("");
  }

  lines.push("| Flow | Type | Trigger | Status | Last Documented |");
  lines.push("|------|------|---------|--------|-----------------|");

  for (const flow of flowData.sort((a, b) =>
    a.apiName.localeCompare(b.apiName)
  )) {
    const docExists = fs.existsSync(path.join(catDir, `${flow.apiName}.md`));
    const nameCell = docExists
      ? `[${flow.apiName}](./${flow.apiName}.md)`
      : flow.apiName;
    let lastDocDate = "";
    if (docExists) {
      const docContent = fs.readFileSync(
        path.join(catDir, `${flow.apiName}.md`),
        "utf8"
      );
      const dateMatch = docContent.match(
        /\*\*Last Documented:\*\*\s*(\d{4}-\d{2}-\d{2})/
      );
      lastDocDate = dateMatch ? dateMatch[1] : "";
    }
    lines.push(
      `| ${nameCell} | ${describeTypeShort(flow)} | ${describeTriggerShort(flow)} | ${flow.status} | ${lastDocDate} |`
    );
  }
  lines.push("");

  const content = lines.join("\n");

  if (dryRun) {
    console.log(`DRY-RUN: Would write ${indexPath}`);
    return;
  }

  ensureDir(catDir);
  fs.writeFileSync(indexPath, content, "utf8");
  console.log(`WROTE: ${indexPath}`);
}

function updateMasterIndex(opts) {
  const dryRun = opts.dryRun || false;

  const allFlows = getAllFlowNames();
  const categoryStats = {};

  for (const flowName of allFlows) {
    const cat = categorize(flowName);
    if (!categoryStats[cat]) {
      categoryStats[cat] = { total: 0, documented: 0 };
    }
    categoryStats[cat].total++;
  }

  for (const cat of Object.keys(categoryStats)) {
    if (!isSkipCategory(cat)) {
      categoryStats[cat].documented = countDocumented(cat);
    }
  }

  const content = generateMasterIndex(categoryStats);
  const indexPath = path.join(DOCS_DIR, "_index.md");

  if (dryRun) {
    console.log(`DRY-RUN: Would write ${indexPath}`);
    return;
  }

  // Preserve "All Documented Flows" table if it exists
  if (fs.existsSync(indexPath)) {
    const existing = fs.readFileSync(indexPath, "utf8");
    const allDocsMatch = existing.match(/(## All Documented Flows[\s\S]*)/);
    if (allDocsMatch) {
      const fullContent = content + allDocsMatch[1];
      fs.writeFileSync(indexPath, fullContent, "utf8");
      console.log(`WROTE: ${indexPath} (preserved All Documented Flows table)`);
      return;
    }
  }

  fs.writeFileSync(indexPath, content, "utf8");
  console.log(`WROTE: ${indexPath}`);
}

// ---------------------------------------------------------------------------
// CLI main
// ---------------------------------------------------------------------------

function main() {
  const opts = {
    dryRun: args.includes("--dry-run"),
    lightweight: args.includes("--lightweight"),
    xmlDescriptionOnly: args.includes("--xml-description-only"),
    indexOnly: args.includes("--index-only"),
  };

  // Parse --category
  let targetCategory = null;
  const catIdx = args.indexOf("--category");
  if (catIdx !== -1 && catIdx + 1 < args.length) {
    targetCategory = args[catIdx + 1];
  }

  // Find flow name argument (positional)
  let flowName = null;
  const flagArgs = new Set([
    "--full",
    "--lightweight",
    "--dry-run",
    "--xml-description-only",
    "--index-only",
    "--category",
    "--help",
    "--metadata-path",
    "--docs-path",
    "--categories-path",
    "--filters-path",
    "--project-name",
  ]);
  for (let i = 0; i < args.length; i++) {
    if (flagArgs.has(args[i])) {
      // Skip flags that take a value
      if (
        [
          "--category",
          "--metadata-path",
          "--docs-path",
          "--categories-path",
          "--filters-path",
          "--project-name",
        ].includes(args[i])
      ) {
        i++;
      }
      continue;
    }
    flowName = args[i];
    break;
  }

  // Determine flow list
  let flowNames = [];
  if (flowName) {
    flowNames = [flowName];
  } else if (targetCategory) {
    const allFlows = getAllFlowNames();
    flowNames = allFlows.filter((n) => categorize(n) === targetCategory);
    if (flowNames.length === 0) {
      console.error(`No flows found in category: ${targetCategory}`);
      process.exit(1);
    }
  } else if (!opts.indexOnly) {
    const allFlows = getAllFlowNames();
    flowNames = allFlows.filter((n) => !isSkipCategory(categorize(n)));
  }

  // --xml-description-only mode
  if (opts.xmlDescriptionOnly) {
    if (flowNames.length === 0) {
      const allFlows = getAllFlowNames();
      flowNames = allFlows.filter((n) => !isSkipCategory(categorize(n)));
    }
    const descriptions = generateXmlDescriptions(flowNames);
    console.log(JSON.stringify(descriptions, null, 2));
    process.exit(0);
  }

  // --index-only mode
  if (opts.indexOnly) {
    if (targetCategory) {
      updateCategoryIndex(targetCategory, opts);
    } else {
      const allFlows = getAllFlowNames();
      const cats = new Set();
      for (const n of allFlows) {
        const c = categorize(n);
        if (!isSkipCategory(c)) cats.add(c);
      }
      for (const cat of [...cats].sort()) {
        updateCategoryIndex(cat, opts);
      }
    }
    updateMasterIndex(opts);
    process.exit(0);
  }

  // Document flows
  const results = [];
  const affectedCategories = new Set();

  for (const fn of flowNames) {
    const result = documentFlow(fn, opts);
    results.push(result);
    if (result.category && !isSkipCategory(result.category)) {
      affectedCategories.add(result.category);
    }
  }

  // Update indexes for affected categories (unless dry-run)
  if (!opts.dryRun) {
    for (const cat of affectedCategories) {
      updateCategoryIndex(cat, opts);
    }
    updateMasterIndex(opts);
  }

  // Summary
  const written = results.filter((r) => r.written).length;
  const skipped = results.filter((r) => r.skipped).length;
  const errors = results.filter((r) => r.error).length;
  const dryRunCount = results.filter((r) => r.dryRun).length;

  console.log("");
  console.log("--- Summary ---");
  if (opts.dryRun) {
    console.log(`Would write: ${dryRunCount}`);
  } else {
    console.log(`Written: ${written}`);
  }
  if (skipped > 0) console.log(`Skipped: ${skipped}`);
  if (errors > 0) console.log(`Errors: ${errors}`);
  if (affectedCategories.size > 0) {
    console.log(
      `Categories updated: ${[...affectedCategories].sort().join(", ")}`
    );
  }
}

main();
